const msg = $input.first().json.message || {};
const text = (msg.text || '').toLowerCase().trim();
const chatId = msg.chat?.id;
const base = 'https://api.loyverse.com/v1.0';
let url, intent;

if (text.includes('venta')) {
  const now = new Date();
  const start = new Date(now.getFullYear(), now.getMonth(), now.getDate());
  url = `${base}/receipts?created_at_min=${start.toISOString()}&limit=250`;
  intent = 'ventas';
} else if (text.includes('inventario') || text.includes('stock')) {
  url = `${base}/inventory?limit=250`;
  intent = 'inventario';
} else if (text.includes('producto')) {
  url = `${base}/items?limit=100`;
  intent = 'productos';
} else {
  url = `${base}/stores`;
  intent = 'ayuda';
}

return [{ json: { url, intent, chatId } }];

const intent = $('Interpretar').first().json.intent;
const chatId = $('Interpretar').first().json.chatId;
const data = $input.first().json;
let respuesta = '';

if (intent === 'ventas') {
  const r = data.receipts || [];
  const total = r.reduce((s, x) => s + (x.total_money || 0), 0);
  respuesta = `\uD83E\uDDFE Ventas de hoy\nRecibos: ${r.length}\nTotal: $${total.toFixed(2)}`;
} else if (intent === 'inventario') {
  const inv = data.inventory_levels || [];
  const bajos = inv.filter(i => (i.in_stock || 0) <= 5);
  respuesta = `\uD83D\uDCE6 Inventario\nVariantes: ${inv.length}\nStock bajo (<=5): ${bajos.length}`;
} else if (intent === 'productos') {
  const items = data.items || [];
  respuesta = `\uD83D\uDED2 Productos: ${items.length}\n` + items.slice(0, 10).map(i => `\u2022 ${i.item_name}`).join('\n');
} else {
  respuesta = 'Hola \uD83D\uDC4B Puedo ayudarte con:\n\u2022 ventas - ventas de hoy\n\u2022 inventario - stock actual\n\u2022 productos - lista de productos';
}

return [{ json: { chatId, respuesta } }];
